1940→+import { promisify } from 'util';
1941→+import { execFile } from 'child_process';
1942→+import { getErrorMessage, isExecError } from '@shared/lib/errors';
1943→+
1944→+const execFileAsync = promisify(execFile);
1945→+
1946→+// Helper: run gh CLI command with timeout, explicit error classification
1947→+export async function runGh(args: string[], options: { cwd: string; timeoutMs?: number }): Promise<
1948→+  { success: true; stdout: string } | { success: false; error: 'gh_not_installed' | 'gh_not_authenticated' | 'timeout' | 'unknown'; message: string }
1949→+> {
1950→+  try {
1951→+    const { stdout, stderr } = await execFileAsync('gh', args, {
1952→+      cwd: options.cwd,
1953→+      encoding: 'utf-8',
1954→+      timeout: options.timeoutMs ?? 5000,
1955→+      env: { ...process.env, GIT_TERMINAL_PROMPT: '0', GH_PROMPT_DISABLED: '1' },
1956→+    });
1957→+    return { success: true, stdout: stdout.trim() };
1958→+  } catch (err: unknown) {
1959→+    if (isExecError(err)) {
1960→+      if (err.code === 'ENOENT') return { success: false, error: 'gh_not_installed', message: 'GitHub CLI (gh) is not installed' };
1961→+      if (err.killed) return { success: false, error: 'timeout', message: 'GitHub CLI command timed out' };
1962→+      const output = `${err.stderr ?? ''} ${err.stdout ?? ''}`.toLowerCase();
1963→+      if (output.includes('gh auth login') || output.includes('not logged into any github hosts'))
1964→+        return { success: false, error: 'gh_not_authenticated', message: 'GitHub CLI is not authenticated' };
1965→+      return { success: false, error: 'unknown', message: err.stderr || err.message || 'Failed to run gh CLI' };
1966→+    }
1967→+    return { success: false, error: 'unknown', message: getErrorMessage(err) };
1968→+  }
1969→+}
1970→+
1971→+// GitHub Check Suite conclusions that indicate a non-passing terminal state.
1972→+// Full GraphQL enum: ACTION_REQUIRED, CANCELLED, FAILURE, NEUTRAL, SKIPPED,
1973→+// STALE, STARTUP_FAILURE, SUCCESS, TIMED_OUT.
1974→+// NEUTRAL/SKIPPED are intentionally non-blocking (count as passing).
1975→+// STALE means re-run is needed (count as pending below).
1976→+export const FAILING_CONCLUSIONS = new Set([
1977→+  'FAILURE', 'ERROR', 'TIMED_OUT', 'STARTUP_FAILURE', 'ACTION_REQUIRED', 'CANCELLED',
1978→+]);
1979→+
1980→+// CheckRun `status` values that indicate the check hasn't completed yet.
1981→+// Note: CheckRun uses `status` field, StatusContext uses `state` field.
1982→+export const PENDING_STATUSES = new Set(['PENDING', 'QUEUED', 'IN_PROGRESS', 'WAITING', 'REQUESTED']);
1983→+
1984→+/**
1985→+ * Classify a single GitHub check (CheckRun or StatusContext) into a uniform status.
1986→+ * GitHub's statusCheckRollup contains two object types:
1987→+ *   - CheckRun (__typename: "CheckRun"): uses `conclusion` + `status`
1988→+ *   - StatusContext (__typename: "StatusContext"): uses `state`
1989→+ */
1990→+export function classifyCheck(check: any): 'passing' | 'failing' | 'pending' {
1991→+  if (check.__typename === 'StatusContext') {
1992→+    if (check.state === 'FAILURE' || check.state === 'ERROR') return 'failing';
1993→+    if (check.state === 'PENDING' || check.state === 'EXPECTED') return 'pending';
1994→+    return 'passing';
1995→+  }
1996→+  // CheckRun
1997→+  if (FAILING_CONCLUSIONS.has(check.conclusion)) return 'failing';
1998→+  if (check.conclusion === 'STALE' || check.conclusion == null || PENDING_STATUSES.has(check.status)) return 'pending';
1999→+  return 'passing';

