2016→+/**
2017→+ * Resolve the PR status for a workspace by inspecting HEAD branch
2018→+ * and querying GitHub via `gh pr list`. Handles fork detection
2019→+ * (origin vs upstream remotes) and prioritizes open > merged > closed PRs.
2020→+ */
2021→+export async function getPrStatus(workspacePath: string): Promise<PrStatusResponse> {
2022→+  // Resolve current branch name
2023→+  let headBranch: string;
2024→+  try {
2025→+    const { stdout } = await execFileAsync('git', ['rev-parse', '--abbrev-ref', 'HEAD'], {
2026→+      cwd: workspacePath, encoding: 'utf-8', timeout: 3000,
2027→+    });
2028→+    headBranch = stdout.trim();
2029→+  } catch {
2030→+    return { has_pr: false, error: null };
2031→+  }
2032→+
2033→+  if (!headBranch || headBranch === 'HEAD') return { has_pr: false, error: null };
2034→+
2035→+  // Resolve origin and upstream remotes for fork support
2036→+  let originUrl: string | null = null;
2037→+  let upstreamUrl: string | null = null;
2038→+  try {
2039→+    const { stdout } = await execFileAsync('git', ['remote', 'get-url', 'origin'], { cwd: workspacePath, encoding: 'utf-8', timeout: 2000 });
2040→+    originUrl = stdout.trim() || null;
2041→+  } catch {}
2042→+  try {
2043→+    const { stdout } = await execFileAsync('git', ['remote', 'get-url', 'upstream'], { cwd: workspacePath, encoding: 'utf-8', timeout: 2000 });
2044→+    upstreamUrl = stdout.trim() || null;
2045→+  } catch {}
2046→+
2047→+  const isFork = upstreamUrl != null && originUrl != null && upstreamUrl !== originUrl;
2048→+
2049→+  // Build list of attempts: try upstream first (for forks), then origin.
2050→+  // Use plain branch name — gh pr list --head does NOT support "owner:branch" syntax.
2051→+  // The --author @me flag already narrows results to the current user's PRs.
2052→+  const attempts: { repoArg: string | null; headArg: string }[] = [];
2053→+  if (isFork) attempts.push({ repoArg: upstreamUrl, headArg: headBranch });
2054→+  attempts.push({ repoArg: originUrl, headArg: headBranch });
2055→+
2056→+  let lastError: string | null = null;
2057→+  let hadSuccessfulResponse = false;
2058→+
2059→+  for (const { repoArg, headArg } of attempts) {
2060→+    const args = ['pr', 'list', '--head', headArg, '--author', '@me', '--state', 'all',
2061→+      '--json', 'number,title,url,state,mergeable,mergeStateStatus,statusCheckRollup,reviewDecision,isDraft'];
2062→+    if (repoArg) args.push('--repo', repoArg);
2063→+
2064→+    const result = await runGh(args, { cwd: workspacePath });
2065→+    if (!result.success) {
2066→+      // Surface specific errors (installed/auth) immediately
2067→+      if (result.error === 'gh_not_installed' || result.error === 'gh_not_authenticated' || result.error === 'timeout') {
2068→+        return { has_pr: false, error: result.error };
2069→+      }
2070→+      lastError = result.error; // Track for surfacing if all attempts fail
2071→+      continue;
2072→+    }
2073→+
2074→+    let prs: any[];
2075→+    try { prs = JSON.parse(result.stdout || '[]'); } catch { continue; }
2076→+    if (!Array.isArray(prs)) continue;
2077→+    hadSuccessfulResponse = true;
2078→+
2079→+    // Priority: OPEN > MERGED > CLOSED. Open PRs are actionable,
2080→+    // merged PRs show archive, closed PRs show a non-actionable status.
2081→+    const openPr = prs.find((pr: any) => pr.state?.toUpperCase() === 'OPEN');
2082→+    const mergedPr = prs.find((pr: any) => pr.state?.toUpperCase() === 'MERGED');
2083→+    const closedPr = prs.find((pr: any) => pr.state?.toUpperCase() === 'CLOSED');
2084→+    const pr = openPr ?? mergedPr ?? closedPr;
2085→+
2086→+    if (pr) {
2087→+      const upperState = pr.state?.toUpperCase();
2088→+      const state: 'open' | 'merged' | 'closed' =
2089→+        upperState === 'MERGED' ? 'merged' :
2090→+        upperState === 'CLOSED' ? 'closed' : 'open';
2091→+
2092→+      // Closed PRs are terminal — no CI or merge status is relevant
2093→+      if (state === 'closed') {
2094→+        return {
2095→+          has_pr: true,
2096→+          pr_number: pr.number,
2097→+          pr_title: pr.title,
2098→+          pr_url: pr.url,
2099→+          pr_state: 'closed',
2100→+          merge_status: 'blocked',
2101→+          is_draft: pr.isDraft === true,
2102→+          has_conflicts: false,
2103→+          ci_status: 'unknown',
2104→+          review_status: 'none',
2105→+          error: null,
2106→+        };
2107→+      }
2108→+
2109→+      let mergeStatus: 'ready' | 'blocked' | 'merged' = 'blocked';
2110→+      if (state === 'merged') mergeStatus = 'merged';
2111→+      else if (pr.mergeable === 'MERGEABLE') mergeStatus = 'ready';
2112→+
2113→+      const rawChecks: any[] = pr.statusCheckRollup ?? [];
2114→+      let ciStatus: 'passing' | 'failing' | 'pending' | 'unknown' = 'unknown';
2115→+      let checksDone = 0;
2116→+      const checksTotal = rawChecks.length;
2117→+      const checkDetails = rawChecks.map((check: any) => ({
2118→+        name: check.name || check.context || 'Unknown',
2119→+        status: classifyCheck(check),
2120→+        url: check.detailsUrl || check.targetUrl || undefined,
2121→+      }));
2122→+      if (rawChecks.length > 0) {
2123→+        const statuses = checkDetails.map((c: any) => c.status);
2124→+        checksDone = statuses.filter((s: string) => s !== 'pending').length;
2125→+        if (statuses.includes('failing')) ciStatus = 'failing';
2126→+        else if (statuses.includes('pending')) ciStatus = 'pending';
2127→+        else ciStatus = 'passing';
2128→+      }
2129→+
2130→+      // Map reviewDecision from GitHub GraphQL enum
2131→+      const reviewMap: Record<string, 'approved' | 'changes_requested' | 'review_required' | 'none'> = {
2132→+        'APPROVED': 'approved', 'CHANGES_REQUESTED': 'changes_requested', 'REVIEW_REQUIRED': 'review_required',
2133→+      };
2134→+      const reviewStatus = reviewMap[pr.reviewDecision ?? ''] ?? 'none';
2135→+
2136→+      return {
2137→+        has_pr: true,
2138→+        pr_number: pr.number,
2139→+        pr_title: pr.title,
2140→+        pr_url: pr.url,
2141→+        pr_state: state,
2142→+        merge_status: mergeStatus,
2143→+        is_draft: pr.isDraft === true,
2144→+        has_conflicts: pr.mergeStateStatus === 'DIRTY',
2145→+        ci_status: ciStatus,
2146→+        checks_done: checksDone,
2147→+        checks_total: checksTotal,
2148→+        checks: checkDetails,
2149→+        review_status: reviewStatus,
2150→+        error: null,
2151→+      };
2152→+    }
2153→+  }
2154→+
2155→+  // If all attempts failed with errors, surface it instead of silently showing "no PR".
2156→+  // lastError is only set for 'unknown' errors (timeout/auth/install return immediately).
2157→+  return { has_pr: false, error: (!hadSuccessfulResponse && lastError) ? 'network' : null };
2158→+}
